import { promises as fs } from "node:fs";
import path from "node:path";

const ROOT = process.cwd();
const STARTER_FILE = path.join(ROOT, "gpt", "gpt_chat_starter.md");
const TEMPLATE_FILE = path.join(ROOT, "gpt", "gpt_new_task_template.md");
const TOPICS_FILE = path.join(ROOT, "gpt", "gpt_topics.md");
const OUTPUT_FILE = path.join(ROOT, "gpt", "gpt_chat_bundle.md");

async function readFile(filePath) {
  return (await fs.readFile(filePath, "utf8")).trim();
}

async function main() {
  const [starter, template, topics] = await Promise.all([
    readFile(STARTER_FILE),
    readFile(TEMPLATE_FILE),
    readFile(TOPICS_FILE),
  ]);

  const bundle = [
    "# GPT Chat Bundle",
    "",
    "> This file is auto-generated by `scripts/generate-gpt-chat-bundle.mjs`.",
    "> Do not edit it manually. Edit source files and regenerate instead.",
    "",
    "## Source: gpt_chat_starter.md",
    "",
    starter,
    "",
    "---",
    "",
    "## Source: gpt_new_task_template.md",
    "",
    template,
    "",
    "---",
    "",
    "## Source: gpt_topics.md",
    "",
    topics,
    "",
  ].join("\n");

  await fs.writeFile(OUTPUT_FILE, bundle, "utf8");
  console.log("Generated gpt/gpt_chat_bundle.md");
}

void main();
